create table tb_book (id bigint generated by default as identity, author varchar(20) not null, genre varchar(15) not null, isbn bigint not null, language varchar(15) not null, photo varchar(255) not null, price double not null, title varchar(70) not null, primary key (id));
create table tb_role (id bigint generated by default as identity, name varchar(255) not null, primary key (id));
create table tb_user (id bigint generated by default as identity, email varchar(255) not null, mobile varchar(255) not null, name varchar(255) not null, password varchar(255) not null, role_id bigint, primary key (id));
alter table tb_user add constraint FKrfmat6i7yc88kv6aqusrqiv6e foreign key (role_id) references tb_role;
